/**
 * @fileoverview Slot-based child identification helpers.
 *
 * Provides utilities for finding child elements via `data-slot` attributes,
 * following the Catalyst/Headless-UI composable pattern.
 *
 * Components can mark structural children with `data-slot="name"`,
 * decoupling the **role** of a child from its **styling class**.
 *
 * @module shared/slots
 */

/**
 * Find the first descendant with a given `data-slot` value.
 *
 * @param {Element} root  Parent element to search within
 * @param {string}  name  Slot name (e.g. 'header', 'body', 'close')
 * @returns {Element|null}
 */
export function querySlot(root, name) {
    return root.querySelector(`[data-slot="${name}"]`);
}

/**
 * Find all descendants with a given `data-slot` value.
 *
 * @param {Element} root  Parent element to search within
 * @param {string}  name  Slot name
 * @returns {Element[]}
 */
export function querySlots(root, name) {
    return [...root.querySelectorAll(`[data-slot="${name}"]`)];
}

/**
 * Collect all slotted children of an element into a name → elements map.
 * Checks both `data-slot` and native `slot` attributes.
 * Children without either attribute go into the 'default' slot.
 *
 * @param {Element} root  Parent element
 * @returns {Object<string, Element[]>}
 */
export function collectSlots(root) {
    const slots = {};
    for (const child of root.children) {
        const name = child.getAttribute('data-slot')
            || child.getAttribute('slot')
            || 'default';
        (slots[name] ??= []).push(child);
    }
    return slots;
}
