/**
 * @fileoverview Dialog state - stack management and reactive state creation.
 * @module module/Dialog/state
 */

import razyui from '../../index.js';
import { CLS } from './constants.js';

// ── Stack management ──────────────────────────
const stack = [];

/**
 * Push a dialog instance onto the global stack and lock body scroll.
 * @param {object} instance
 */
export function pushStack(instance) {
    stack.push(instance);
    updateBodyScroll();
}

/**
 * Remove a dialog instance from the global stack and restore body scroll.
 * @param {object} instance
 */
export function popStack(instance) {
    const idx = stack.indexOf(instance);
    if (idx !== -1) stack.splice(idx, 1);
    updateBodyScroll();
}

/**
 * Return the topmost dialog on the stack (or null).
 * @returns {object|null}
 */
export function topOfStack() {
    return stack.length > 0 ? stack[stack.length - 1] : null;
}

/**
 * Return the current stack size (used for z-index calculation).
 * @returns {number}
 */
export function getStackSize() {
    return stack.length;
}

/**
 * Return a reference to the internal stack array.
 * Used by Dialog.closeAll().
 * @returns {object[]}
 */
export function getStack() {
    return stack;
}

/** Toggle body scroll-lock based on stack occupancy. */
function updateBodyScroll() {
    if (stack.length > 0) {
        razyui(document.body).css('overflow', 'hidden');
    } else {
        razyui(document.body).css('overflow', '');
    }
}

// ── Reactive state ────────────────────────────

/**
 * Create the reactive `{ locked, loading }` state for a dialog instance.
 * @param {object} razyui  The razyui runtime
 * @returns {Array} razyui.state() tuple - [stateRef, setState, stateSet]
 */
export function createReactiveState(razyui) {
    return razyui.state({
        locked: false,
        loading: false,
    });
}

/**
 * Wire state effects that toggle CSS classes on DOM elements.
 *
 * @param {object} stateSet   razyui.state() return value
 * @param {HTMLElement} footerEl  Footer element containing buttons
 * @param {HTMLElement} dialogEl  Dialog box element
 */
export function wireEffects(stateSet, footerEl, dialogEl) {
    // Locked state: disable buttons, add is-locked class
    stateSet.effect(function () {
        const btns = footerEl.querySelectorAll('.' + CLS.BTN);
        btns.forEach(b => {
            b.disabled = !!this.locked;
        });
        razyui(dialogEl).toggleClass(CLS.LOCKED, !!this.locked);
    });

    // Loading state: add is-loading class
    stateSet.effect(function () {
        razyui(dialogEl).toggleClass(CLS.LOADING, !!this.loading);
    });
}
