/**
 * @fileoverview Dialog constants - CSS classes, defaults, SVG icons, spell patterns.
 * @module module/Dialog/constants
 */

import { Z_DIALOG, TRANSITION_DURATION_MS, ICON_CLOSE_16_24 } from '../shared/tokens/index.js';
import { TRUNCATE, SCROLL_BODY, ICON_BTN_RESET, TRANSITION_COLORS, FOCUS_RING } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** Base z-index for dialog stacking */
export const BASE_Z = Z_DIALOG;

/** Transition fallback timeout (ms) */
export const TRANSITION_TIMEOUT = TRANSITION_DURATION_MS;

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    size: 'md',
    closable: true,
    overlayClose: true,
});

/** CSS class names */
export const CLS = Object.freeze({
    OVERLAY:      'dialog-overlay',
    BOX:          'dialog-box',
    HEADER:       'dialog-header',
    TITLE:        'dialog-title',
    CLOSE:        'dialog-close',
    BODY:         'dialog-body',
    FOOTER:       'dialog-footer',
    PROMPT:       'dialog-prompt',
    PROMPT_INPUT: 'dialog-prompt-input',
    BTN_GROUP:    'dialog-btn-group',
    BTN_GROUP_LEFT: 'dialog-btn-group-left',
    BTN:          'dialog-btn',
    ACTIVE:       'is-active',
    LOCKED:       'is-locked',
    LOADING:      'is-loading',
});

/** Semantic part names for JIT styling overrides. */
export const PART = defineParts('Dialog', {
    OVERLAY     : { class: 'dialog-overlay', aliases: ['overlay'] },
    BOX         : { class: 'dialog-box', aliases: ['box', 'root', 'container'] },
    HEADER      : { class: 'dialog-header', aliases: ['header'] },
    TITLE       : { class: 'dialog-title', aliases: ['title'] },
    CLOSE       : { class: 'dialog-close', aliases: ['close', 'close-btn'] },
    BODY        : { class: 'dialog-body', aliases: ['body'] },
    FOOTER      : { class: 'dialog-footer', aliases: ['footer'] },
    PROMPT      : { class: 'dialog-prompt' },
    PROMPT_INPUT: { class: 'dialog-prompt-input' },
    BTN_GROUP   : { class: 'dialog-btn-group' },
    BTN_GROUP_LEFT: { class: 'dialog-btn-group-left' },
    BTN         : { class: 'dialog-btn', aliases: ['btn', 'button'] },
});

PART.OVERLAY.jit  = 'fixed [inset:0] flex items-center justify-center [background:rgba(0,0,0,0)] [transition:background_.15s_cubic-bezier(0.4,0,0.2,1)] [padding:1.5rem] {is-active}:bg-[var(--rui-overlay)]';
PART.BOX.jit      = 'relative flex flex-col [max-height:calc(100vh_-_1.5rem*2)] [border:1px_solid_var(--rui-border)] rounded-[var(--dlg-radius)] bg-[var(--rui-bg)] [box-shadow:var(--rui-shadow-lg)] [font-family:inherit] text-[var(--dlg-font-size)] fg-[var(--rui-text)] [opacity:0] [transform:scale(0.95)_translateY(8px)] [transition:opacity_.15s_cubic-bezier(0.4,0,0.2,1),transform_.15s_cubic-bezier(0.4,0,0.2,1)] {is-active}:[opacity:1] {is-active}:[transform:scale(1)_translateY(0)] {is-loading}:pointer-events-none {dialog-sm}:[width:var(--dlg-sm-width)] {dialog-md}:[width:var(--dlg-md-width)] {dialog-lg}:[width:var(--dlg-lg-width)] {dialog-xl}:[width:var(--dlg-xl-width)] {dialog-full}:[width:calc(100vw_-_1.5rem*2)] {dialog-full}:[height:calc(100vh_-_1.5rem*2)]';
PART.HEADER.jit   = 'flex items-center gap-[var(--dlg-header-gap)] [padding:var(--dlg-header-padding-y)_var(--dlg-header-padding-x)] [border-bottom:1px_solid_var(--rui-border)] shrink-0';
PART.TITLE.jit    = TRUNCATE + ' text-[var(--dlg-title-font-size)] fw-[var(--dlg-title-font-weight)] fg-[var(--rui-text)] [line-height:var(--dlg-title-line-height)]';
PART.CLOSE.jit    = ICON_BTN_RESET + ' w-[var(--dlg-close-btn-size)] [height:28px] rounded-[var(--dlg-close-btn-radius)] fg-[var(--rui-text-muted)] ' + TRANSITION_COLORS + ' hover:bg-[var(--rui-bg-hover)] hover:fg-[var(--rui-text)]';
PART.BODY.jit     = SCROLL_BODY + ' p-[var(--dlg-body-padding)] [line-height:var(--dlg-body-line-height)] fg-[var(--rui-text)] [&_p]:[margin:0_0_0.5rem] [&_p:last-child]:[margin-bottom:0]';
PART.FOOTER.jit   = 'flex [justify-content:flex-end] [padding:var(--dlg-header-padding-y)_var(--dlg-header-padding-x)] [border-top:1px_solid_var(--rui-border)] shrink-0 empty:hidden ^{is-loading}:[opacity:0.5]';
PART.PROMPT.jit   = '[margin-top:0.5rem]';
PART.PROMPT_INPUT.jit = 'block w-full [padding:0.5rem_0.75rem] [border:1px_solid_var(--rui-border)] rounded-[var(--dlg-close-btn-radius)] bg-[var(--rui-bg)] [font:inherit] text-[var(--dlg-font-size)] fg-[var(--rui-text)] [line-height:1.25] [box-sizing:border-box] [transition:border-color_.15s,box-shadow_.15s] ' + FOCUS_RING + ' placeholder:fg-[var(--rui-text-muted)]';
PART.BTN_GROUP.jit = 'flex gap-[var(--dlg-header-gap)]';
PART.BTN_GROUP_LEFT.jit = 'flex gap-[var(--dlg-header-gap)] [margin-right:auto]';
PART.BTN.jit      = 'inline-flex items-center justify-center [padding:0.5rem_1rem] [border:1px_solid_var(--rui-border)] rounded-[var(--dlg-close-btn-radius)] bg-[var(--rui-bg)] [font:inherit] text-[var(--dlg-font-size)] fw-500 fg-[var(--rui-text)] [line-height:1.25] cursor-pointer [transition:background_.15s,border-color_.15s,color_.15s,opacity_.15s] text-nowrap hover:bg-[var(--rui-bg-hover)] hover:[border-color:var(--rui-border-strong)] disabled:[opacity:0.5] disabled:cursor-default ^{is-locked}:[opacity:0.6] ^{is-loading}:cursor-wait {dialog-btn-accent}:bg-[var(--rui-accent)] {dialog-btn-accent}:[border-color:var(--rui-accent)] {dialog-btn-accent}:fg-[var(--rui-on-accent)] {dialog-btn-accent}:hover:bg-[var(--rui-accent-hover)] {dialog-btn-accent}:hover:[border-color:var(--rui-accent-hover)] {dialog-btn-muted}:bg-[var(--rui-bg-raised)] {dialog-btn-muted}:[border-color:var(--rui-border)] {dialog-btn-muted}:fg-[var(--rui-text-secondary)] {dialog-btn-muted}:hover:bg-[var(--rui-bg-hover)] {dialog-btn-muted}:hover:fg-[var(--rui-text)] {dialog-btn-danger}:bg-[var(--rui-danger)] {dialog-btn-danger}:[border-color:var(--rui-danger)] {dialog-btn-danger}:fg-[var(--rui-on-danger)] {dialog-btn-danger}:hover:bg-[var(--rui-danger-hover)] {dialog-btn-danger}:hover:[border-color:var(--rui-danger-hover)] {dialog-btn-success}:bg-[var(--rui-success)] {dialog-btn-success}:[border-color:var(--rui-success)] {dialog-btn-success}:fg-[var(--rui-on-success)] {dialog-btn-success}:hover:bg-[var(--rui-success-hover)] {dialog-btn-success}:hover:[border-color:var(--rui-success-hover)]';

/** SVG icon markup */
export const SVG = Object.freeze({
    CLOSE: ICON_CLOSE_16_24,
});

/** razyui.spell() patterns */
export const SPELL = Object.freeze({
    DIALOG:    'div.dialog-overlay[data-slot=overlay](div.dialog-box[data-slot=box](div.dialog-header[data-slot=header](div.dialog-title[data-slot=title]),div.dialog-body[data-slot=body],div.dialog-footer[data-slot=footer]))',
    CLOSE_BTN: 'button.dialog-close[data-slot=close]',
    PROMPT:    'div.dialog-prompt[data-slot=prompt](input.dialog-prompt-input[data-slot=prompt-input])',
});

/** Focusable elements selector (for tab-trap) */
export const FOCUSABLE_SELECTOR =
    'button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';