/**
 * @fileoverview Dialog events - global Escape handler and overlay-click binding.
 * @module module/Dialog/events
 */

import razyui from '../../index.js';
import { topOfStack } from './state.js';
import { FOCUSABLE_SELECTOR } from './constants.js';

// ── Global Escape handler ──────────────────────
let escBound = false;

/**
 * Bind the global Escape-key handler (once).
 * Pressing Escape closes the topmost closable dialog.
 */
export function bindEscapeHandler() {
    if (escBound) return;
    escBound = true;
    razyui(document).on('keydown', (e) => {
        if (e.key === 'Escape') {
            const top = topOfStack();
            if (top && top.closable) {
                top.close();
            }
        }
    });
}

/**
 * Bind a mousedown handler on the overlay so pressing outside the dialog
 * box closes the dialog.  Using mousedown (instead of click) prevents
 * accidental closes when the user presses inside the dialog and releases
 * outside — only a press that *starts* on the overlay will dismiss it.
 *
 * @param {HTMLElement} overlay   Overlay element
 * @param {Function}    closeFn  Callback to close the dialog
 */
export function bindOverlayClose(overlay, closeFn) {
    razyui(overlay).on('mousedown', (e) => {
        if (e.target === overlay) closeFn();
    });
}

/**
 * Install a keyboard tab-trap so focus cycles within the dialog.
 *
 * @param {HTMLElement} overlay  Overlay element (receives keydown)
 * @param {HTMLElement} dialog   Dialog box (queried for focusable children)
 */
export function setupTabTrap(overlay, dialog) {
    razyui(overlay).on('keydown', (e) => {
        if (e.key !== 'Tab') return;
        const focusable = dialog.querySelectorAll(FOCUSABLE_SELECTOR);
        if (focusable.length === 0) return;
        const first = focusable[0];
        const last = focusable[focusable.length - 1];
        if (e.shiftKey) {
            if (document.activeElement === first) {
                e.preventDefault();
                last.focus();
            }
        } else {
            if (document.activeElement === last) {
                e.preventDefault();
                first.focus();
            }
        }
    });
}
